import{_ as t,o as e,c as r,a2 as i}from"./chunks/framework.Cr-Z7ngm.js";const b=JSON.parse('{"title":"如何开通期权交易权限","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"derivatives/enable-options.md","filePath":"zh-CN/derivatives/enable-options.md"}'),l={name:"derivatives/enable-options.md"};function o(d,a,n,s,h,p){return e(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="如何开通期权交易权限" tabindex="-1">如何开通期权交易权限 <a class="header-anchor" href="#如何开通期权交易权限" aria-label="Permalink to &quot;如何开通期权交易权限&quot;">​</a></h1><p>长桥美股期权交易需要单独开通权限。已持有香港或新加坡综合账户的用户均可申请。</p><h2 id="开通步骤" tabindex="-1">开通步骤 <a class="header-anchor" href="#开通步骤" aria-label="Permalink to &quot;开通步骤&quot;">​</a></h2><ol><li>打开长桥 App，进入「资产」页面</li><li>点击右上角「全部功能」</li><li>找到「开通功能」或「开户资料」入口，选择「美股期权」</li><li>阅读并确认期权交易风险披露书</li><li>完成适当性评估问卷（含投资经验、风险承受能力等题目）</li><li>提交申请，等待审核</li></ol><p>审核通常在 1 个工作日内完成，审核结果会通过 App 通知推送。</p><h2 id="权限级别" tabindex="-1">权限级别 <a class="header-anchor" href="#权限级别" aria-label="Permalink to &quot;权限级别&quot;">​</a></h2><p>长桥按风险程度提供分级期权权限：</p><table tabindex="0"><thead><tr><th>级别</th><th>可操作策略</th></tr></thead><tbody><tr><td>一级</td><td>买入看涨（Long Call）、买入看跌（Long Put）—— 仅需支付权利金</td></tr><tr><td>二级</td><td>一级 + 有持仓担保的卖出期权（Covered Call、Cash-secured Put）</td></tr><tr><td>三级</td><td>二级 + 裸卖出期权（Naked Call / Naked Put）—— 需要较高保证金</td></tr></tbody></table><p>新用户通常先获得一级权限。如需升级，可在 App 内重新提交申请并更新适当性评估。</p><h2 id="开通失败与审核答疑" tabindex="-1">开通失败与审核答疑 <a class="header-anchor" href="#开通失败与审核答疑" aria-label="Permalink to &quot;开通失败与审核答疑&quot;">​</a></h2><p><strong>Q：提交申请后多久可以开始交易？</strong><br> 审核通过后即可开始交易。审核通常在提交当日或次日完成（工作日）。</p><p><strong>Q：申请被拒怎么办？</strong><br> 拒绝原因通常是适当性评估分数不足或账户条件未满足。可联系客服了解具体原因，部分情况下可补充说明后重新提交。</p><p><strong>Q：港股窝轮和牛熊证需要单独申请吗？</strong><br> 不需要，港股窝轮和牛熊证属于正股交易范畴，持有香港账户即可直接交易，无需额外开通权限。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/derivatives/期权基础">期权基础</a></li><li><a href="/derivatives/期权买方">期权买方</a></li><li><a href="/derivatives/期权卖方">期权卖方</a></li></ul>',15)])])}const u=t(l,[["render",o]]);export{b as __pageData,u as default};
